SELECT DISTINCT u.user_name
FROM users u
JOIN meeting_logs ml ON ml.attendance LIKE '%' || u.user_id || '%';

SELECT COUNT(license_id) AS TotalApprovedLicenses
FROM licenses
WHERE action = 'APPROVED' AND action_by = 'Licenses Committee';

SELECT license_type_name
FROM license_types
WHERE license_type_name LIKE 'Class%' AND renewal_process LIKE '%Submit a renewal application%';

SELECT *
FROM licenses
WHERE action = 'approved' AND action_by IN (SELECT committee_name FROM committees);

SELECT COUNT(*) 
FROM users 
WHERE user_id NOT IN (SELECT chairperson_id FROM committees);
